import axios from 'axios';
import { getStoredToken, setStoredToken } from './storage';

export async function refreshToken(): Promise<string> {
  const stored = getStoredToken();
  if (!stored?.refreshToken) throw new Error('no refresh token');
  const resp = await axios.post('/api/auth/refresh', {
    refresh_token: stored.refreshToken,
  });
  setStoredToken(resp.data);
  return resp.data.access_token;
}

import axios from 'axios';
import { refreshToken } from './refresh';

axios.interceptors.response.use(undefined, async (err) => {
  if (err.response?.status === 401 && !err.config._retried) {
    err.config._retried = true;
    const newToken = await refreshToken();
    err.config.headers.Authorization = `Bearer ${newToken}`;
    return axios.request(err.config);
  }
  throw err;
});

// POST /api/auth/refresh
// 정책: refresh_token 은 1회용. 재사용 시 즉시 무효화 (theft detection)
router.post('/refresh', async (req, res) => {
  const rt = await db.refreshTokens.findValid(req.body.refresh_token);
  if (!rt) return res.status(401).send({ error: 'invalid_or_used' });
  await db.refreshTokens.revoke(rt.id);
  const newPair = issueTokens(rt.userId);
  await db.refreshTokens.insert(newPair.refreshToken);
  res.json(newPair);
});

const KEY = 'auth.tokens';
export function getStoredToken() {
  const raw = localStorage.getItem(KEY);
  return raw ? JSON.parse(raw) : null;
}
export function setStoredToken(t: any) {
  localStorage.setItem(KEY, JSON.stringify(t));
}
export function clearTokens() {
  localStorage.removeItem(KEY);
}

