axios.interceptors.response.use(undefined, async (err) => {
  if (err.response?.status !== 401) throw err;
  if (err.config._retried) throw err; // 재시도 1회 한정
  // refresh 자체의 401 (refresh_token 무효) 은 재귀 차단
  if (err.config.url?.endsWith('/api/auth/refresh')) throw err;
  err.config._retried = true;
  try {
    const newToken = await refreshToken();
    err.config.headers.Authorization = `Bearer ${newToken}`;
    return axios.request(err.config);
  } catch (refreshErr) {
    // refresh 실패 = 세션 종료. clearTokens 후 throw — caller (e.g. router guard) 가 로그인으로 유도
    const { clearTokens } = await import('./storage');
    clearTokens();
    throw refreshErr;
  }
});

