import { describe, it, expect, vi, beforeEach } from 'vitest';
import axios from 'axios';
import { refreshToken } from './refresh';

vi.mock('./storage', () => ({
  getStoredToken: () => ({ refreshToken: 'rt-1' }),
  setStoredToken: vi.fn(),
}));

describe('refreshToken — concurrent callers', () => {
  beforeEach(() => vi.restoreAllMocks());

  it('makes only one network call when 5 callers race', async () => {
    const post = vi.spyOn(axios, 'post').mockResolvedValue({
      data: { access_token: 'at-new', refreshToken: 'rt-new' },
    });
    const results = await Promise.all([
      refreshToken(), refreshToken(), refreshToken(),
      refreshToken(), refreshToken(),
    ]);
    expect(post).toHaveBeenCalledTimes(1);
    expect(new Set(results).size).toBe(1);
  });

  it('clears inflight after rejection so next caller retries', async () => {
    vi.spyOn(axios, 'post').mockRejectedValueOnce(new Error('net')).mockResolvedValueOnce({
      data: { access_token: 'at-2', refreshToken: 'rt-2' },
    });
    await expect(refreshToken()).rejects.toThrow('net');
    await expect(refreshToken()).resolves.toBe('at-2');
  });
});

